sp_rectangle_menu_item.record_script:
var bannerAwaitingARMPromotion = function(data){
  var u = gs.getUser().getID();

  var tbf = new TaskerBannerFilters();

  tbf.label = 'Awaiting ARM Promotion';
  tbf.table = 'x_153465_discovert_war_sar_reporting';
  tbf.filter = 'status=submitted^assigneeDYNAMIC90d1921e5f510100a9ad2572f2b477fe';
  tbf.orderDesc = 'sys_updated_on';
  tbf.idField = 'sys_id';
  tbf.displayFieldName = 'number';
  tbf.displayFieldName2 = 'slug_line';
  tbf.linkView = 'sp';
  tbf.pageId = 'discovertasker_taskdetails';
  tbf.viewAllLinkTitle = gs.getMessage('View all requests');
  tbf.viewAllLinkPageId = 'discovertasker_detailsdrilldown';
  tbf.viewAllLinkView = 'default';
  tbf.viewAllLinkFilter = 'assignee=' + u + '^statusINsubmitted%5EEQ';
  tbf.createBanner();
  data.items = tbf.items;
  data.record_watchers = tbf.record_watchers;
  data.count = tbf.count;
}

bannerAwaitingARMPromotion(data);
